  render: ({
    onClose,
    ...props
  }) => {
    const [visible, setVisible] = useState(true);
    return <>
        <Button onClick={() => {
        setVisible(true);
      }} label="Open Modal" />
        <Modal data-testid="default-modal" {...props} onClose={() => {
        onClose?.();
        setVisible(false);
      }}>
          <Modal.Content padding overflowY="auto" divider="none">
            <GlobalContent />
          </Modal.Content>
        </Modal>
      </>;
  },
  args: {
    headerTitle: "Default story title",
    onClose: fn(),
    defaultVisible: true,
    variant: "dialog",
    height: "s"
  },
  argTypes: ModalArgTypes,
  parameters
